INSERT INTO public."MasterBrand" (code, name) 
VALUES
(0, 'Clear - No brand exists for the vehicle.'),
(1, 'Flood damage - Vehicle damaged by freshwater flood (or it is unknown whether the damage was caused by fresh water or salt water).'),
(2, 'Fire damage - Vehicle damaged by fire.'),
(3, 'Hail damage - Vehicle damaged by hail.'),
(4, 'Salt water damage - Vehicle damaged by saltwater flood.'),
(5, 'Vandalism - Vehicle damaged by vandals.'),
(6, 'Kit Vehicle - A Vehicle that has been built by combining a chassis with a different (non-matching VIN) frame, engine, and body parts. The VIN on the chassis is used as the vehicle''s VIN.'),
(7, 'Dismantled - The vehicle can only be sold as parts and cannot be legally driven.'),
(8, 'Junk - The vehicle is incapable of safe operation for use on the roads or highways and has no resale value except as a source of parts or scrap, or the vehicle''s owner has irreversibly designated the vehicle as a source of parts or scrap. This vehicle shall never be titled or registered. Also known as nonrepairable, scrapped, or destroyed.'),
(9, 'Rebuilt - The vehicle, previously branded "salvage", has passed anti-theft and safety inspections, or other jurisdiction procedures, to ensure the vehicle was rebuilt to required standards. Also known as prior salvage (salvaged).'),
(10, 'Reconstructed - A vehicle that has been permanently altered from original construction by removing, adding, or substituting major components.'),
(11, 'Salvage - Any vehicle which has been wrecked, destroyed or damaged, to the extent that the total estimated or actual cost of parts and labor to rebuild or reconstruct the vehicle to its pre-accident condition and for legal operation on roads or highways exceeds a jurisdiction-defined percentage of the retail value of the vehicle. The retail value of the vehicle is determined by a current edition of a nationally recognized compilation (to include automated data bases) of retail values. Salvage--Damage or Not Specified also includes any vehicle to which an insurance company acquires ownership pursuant to a damage settlement, or any vehicle that the vehicle''s owner may wish to designate as a salvage vehicle by obtaining a salvage title, without regard to extent of the vehicle''s damage and repairs, or any vehicle for which the jurisdiction cannot distinguish the reason the vehicle was designated salvage.'),
(12, 'Test Vehicle - The vehicle is built and retained by the manufacturer or has been retrofitted by a third party for testing and may not be considered roadworthy after testing is complete.'),
(13, 'Refurbished - Any vehicle modified by the installation of a new cab and chassis for the existing coach which has been renovated, resulting in a vehicle of greater value or a vehicle with a new style.'),
(14, 'Collision - Vehicle damaged by collision.'),
(15, 'Reserved. - Eliminated in favor of code 09. Code 15 was "Prior Salvage."'),
(16, 'Salvage Retention - The vehicle is branded salvage and is kept by the owner.'),
(17, 'Prior Taxi - Vehicle previously registered as a taxi.'),
(18, 'Prior Police - Vehicle previously registered as a police vehicle.'),
(19, 'Original Taxi - Vehicle is currently registered as a taxi.'),
(20, 'Original Police - Vehicle is currently registered as a police vehicle.'),
(21, 'Re-manufactured - Vehicle was reconstructed by the manufacturer.'),
(22, 'Reserved. Eliminated - Has been replaced by brands "45" and "46", as of 6/25/01'),
(23, 'Warranty Return - Vehicle returned to the manufacturer because of a breach in the warranty.'),
(24, 'Antique - The vehicle is over 50 years old.'),
(25, 'Classic - The vehicle is over 20 years old and adheres to other jurisdiction-specific criteria, e.g., vehicle make, condition, etc.'),
(26, 'Agricultural Vehicle - The vehicle will primarily be operated on private roads for agricultural purposes.'),
(27, 'Logging Vehicle - The vehicle will primarily be operated on private roads for logging purposes.'),
(28, 'Street Rod - The vehicle has been modified to not conform with the manufacturer''s specifications, and the modifications adhere to jurisdiction-specific criteria.'),
(29, 'Vehicle Contains Reissued VIN - The chassis VIN has been reissued, i.e. the same VIN is reused.'),
(30, 'Replica - A vehicle with a body built to resemble and be a reproduction of another vehicle of a given year and given manufacturer.'),
(31, 'Totaled - A vehicle that is declared a total loss by a jurisdiction or an insurer that is obligated to cover the loss or that the insurer takes possession of or title to.'),
(32, 'Owner Retained - A vehicle that has been declared by the insurance company to be a total loss but the owner maintains possession and ownership of the vehicle.'),
(33, 'Reserved. Eliminated. Bond Posted - The insurance company has issued a bond on the vehicle because the ownership of the vehicle cannot be proven; this allows the vehicle to be sold and titled. Note: This brand is not valid after January 17, 2003.'),
(34, 'Memorandum Copy - The title document is a facsimile title and not the active (original or duplicate) title document.'),
(35, 'Reserved. Eliminated. Parts Only - The vehicle may only be used for parts. This code is no longer used, use "07 - Dismantled".'),
(36, 'Recovered Theft - The vehicle was previously titled as salvage due to theft. The Vehicle has been repaired and inspected (or complied with other jurisdiction procedures) and may be legally driven.'),
(37, 'Undisclosed Lien - The vehicle has entered the titling jurisdiction from a jurisdiction that does not disclose lien-holder information on the title. The titling jurisdiction may issue a new title without this brand if no notice of a security interest in the vehicle is received, within a jurisdiction defined time frame. Note: This brand is not valid after January 17, 2003.'),
(38, 'Prior Owner Retained - A vehicle that was previously branded owner retained and was sold. The new owner''s title contains this brand.'),
(39, 'Vehicle Non-conformity Uncorrected - A non-safety defect reported to the jurisdiction by the vehicle manufacturer remains uncorrected.'),
(40, 'Vehicle Non-conformity Corrected - A non-safety defect reported to the jurisdiction by the vehicle manufacturer has been corrected.'),
(41, 'Vehicle Safety Defect Uncorrected - A safety defect reported to the jurisdiction by the vehicle manufacturer remains uncorrected.'),
(42, 'Vehicle Safety Defect Corrected - A safety defect reported to the jurisdiction by the vehicle manufacturer has been corrected.'),
(43, 'VIN replaced by a new state assigned VIN. A title should not be issued for the VIN. This brand can be issued for rebuilt vehicles.'),
(45, 'Gray Market - Vehicle was manufactured for use outside the United States and has been brought into the United States. The vehicle is not in compliance with applicable federal standards.'),
(46, 'Gray Market - Vehicle was manufactured for use outside the United States and has been brought into the United States. The vehicle is in compliance with applicable federal standards.'),
(47, 'Manufacturer Buy Back - A vehicle that has been bought back by the manufacturer under jurisdiction defined regulations or laws, such as lemon laws. For example, the manufacturer could be obligated to buy back the vehicle when a specified number of repair attempts fails to correct a major problem on a new vehicle, or if a new vehicle has been out of service for repair for the same problem for a cumulative period of 30 days or more, within one year of purchase.'),
(48, 'Former Rental'),
(49, 'Salvage--Stolen - Any vehicle the reporting jurisdiction considers salvage because an insurance company has acquired ownership pursuant to a settlement based on the theft of the vehicle.'),
(50, 'Salvage--Reasons Other Than Damage or Stolen - Any vehicle the reporting jurisdiction considers salvage based on criteria, such as abandonment, not covered by the Salvage--Damage or Not Specified and Salvage--Stolen brands. Note.--Percent of damage is not reported with brand code 50.'),
(51, 'Disclosed Damage - The vehicle has sustained damage to the extent that the damage is required to be disclosed under the jurisdiction''s damage disclosure law.'),
(52, 'Prior Non-Repairable / Repaired - A vehicle constructed by repairing a vehicle that has been destroyed or declared to be non-repairable or otherwise declared to not be eligible for titling because of the extent of damage to the vehicle but has been issued a title pursuant to state law after falling within this criterion with this brand on the face of the certificate of title.'),
(53, 'Crushed - The frame or chassis of the vehicle has been crushed or otherwise destroyed so that it is physically impossible to use it in constructing a vehicle.'),
(55, 'Hazardous Substance Contaminated Vehicle - The jurisdiction has determined that the vehicle has been contaminated by a hazardous substance and is unsafe for use. Excluding flood damaged vehicles. A hazardous substance is any substance that could diminish the safety of the vehicle or cause injury to its occupants. The hazardous substance has one or more, but is not limited to the following intrinsic hazardous properties: Explosiveness, Flammability, Ability to oxidize (accelerate a fire), Human toxicity (acute or chronic), Corrosiveness (to human tissue or metal), Eco toxicity (with or without bioaccumulation), Capacity, on contact with air or water, to develop one or more of the above properties.'),
(56, 'Export Only Vehicle - A salvage or junk vehicle determined for exportation outside of the United States and/or its territories, is not eligible for re-title/re-registration for on-road use in the United States.'),
(68, 'Odometer - Actual - The true mileage for the vehicle. The odometer has not been tampered with, reached its mechanical limits, or been altered.'),
(69, 'Odometer - Not Actual - The odometer reading is known to be other than the true mileage for the vehicle.'),
(70, 'Odometer - Not Actual - Odometer tampering verified - The odometer reading is known to be other than the true mileage for the vehicle, due to tampering.'),
(71, 'Exempt from Odometer Disclosure - The vehicle falls within criteria that allow it to change ownership without disclosure of the odometer reading.'),
(72, 'Odometer - Exceeds Mechanical Limits - The odometer reading is less than the true mileage of the vehicle because the odometer cannot display the total number of true miles.'),
(73, 'Odometer may be Altered - The titling authority has reason to believe that the odometer reading does not reflect the true mileage of the vehicle because of an alteration to the odometer.'),
(74, 'Odometer Replaced - The odometer in the vehicle is not the odometer put in the vehicle when manufactured.'),
(75, 'Odometer - Reading at Time of Renewal - The odometer reading was recorded when the registration was renewed.'),
(76, 'Odometer Discrepancy - The titling authority has reason to believe that the odometer reading does not reflect the true mileage of the vehicle because of known previous recorded values of odometer for the vehicle.'),
(77, 'Odometer - Call Title Division - The titling authority knows of some problem with the odometer reading that it cannot print on a title. Titling authority will discuss the problem (manual process) with authorized inquirers.'),
(78, 'Odmtr-Rectify Prev. Exceeds Mechanical Limit Brand - A state other than the brander corrected brand 72.'),
(90, 'Pending Junk Automobile - CARS.gov - The National Highway Traffic Safety Administration (NHTSA) Consumer Assistance to Recycle and Save (CARS) program is processing an application which, if approved, will render this vehicle incapable of operating on public streets, roads, and highways. The vehicle will have no value except as a source of parts or scrap, shall be crushed or shredded within a specified time period (including the engine block), and shall not be exported prior to crushing or shredding. For additional information concerning the CARS program visit CARS.gov.'),
(91, 'Junk Automobile - CARS.gov - Pursuant to the Consumer Assistance to Recycle and Save Act of 2009 (CARS) this vehicle is incapable of operating on public streets, roads, and highways. The vehicle has no value except as a source of parts or scrap, shall be crushed or shredded within a specified time period (including the engine block), and shall not be exported prior to crushing or shredding. For additional information concerning the CARS program visit CARS.gov.');
